CustomField.formula:
IF( INCLUDES(Statut__c, "Terminé"), "✅ Projet clôturé",
IF( OR(ISBLANK(startDate__c), ISBLANK(endDate__c)), "⚪ Dates non définies",
IF( /* Priorité au statut : si En cours, on calcule la fin peu importe la date de début */ INCLUDES(Statut__c, "En cours"), IF( (endDate__c - TODAY()) < 0, "🏁 échéance dépassée (" & TEXT(ABS(endDate__c - TODAY())) & " jours de retard)", IF( (endDate__c - TODAY()) = 0, "🚨 𝐃𝐄𝐑𝐍𝐈𝐄𝐑 𝐉𝐎𝐔𝐑!", "⏳ 𝐉 — " & SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(SUBSTITUTE( TEXT(endDate__c - TODAY()), "0", "𝟎"), "1", "𝟏"), "2", "𝟐"), "3", "𝟑"), "4", "𝟒"), "5", "𝟓"), "6", "𝟔"), "7", "𝟕"), "8", "𝟖"), "9", "𝟗")
) ),
/* Si pas En cours et date dans le futur */ IF( TODAY() < startDate__c, "🕒 (𝐃𝐞́𝐦𝐚𝐫𝐫e 𝐥𝐞 " & IF(DAY(startDate__c) < 10, "0", "") & TEXT(DAY(startDate__c)) & "/" & IF(MONTH(startDate__c) < 10, "0", "") & TEXT(MONTH(startDate__c)) & "/" & TEXT(YEAR(startDate__c)) & " — dans " & TEXT(startDate__c - TODAY()) & " jrs)", "⚠️ Démarrage manuel requis" ) ) ) )
